// Census ACS industry variables (2022 5-year estimates)
const INDUSTRY_VARS = {
  'C24050_001E': 'Total Employed',
  'C24050_007E': 'Professional & Technical',
  'C24050_013E': 'Healthcare & Social Assistance',
  'C24050_019E': 'Retail Trade & Sales',
  'C24050_025E': 'Construction',
  'C24050_031E': 'Manufacturing',
  'C24050_037E': 'Transportation & Warehousing',
  'C24050_043E': 'Finance & Real Estate',
  'C24050_049E': 'Education & Training',
  'C24050_055E': 'Leisure & Hospitality',
};

// ============================================================================
// Function: Call Census API
// ============================================================================
async function getCensusIndustries(state, county, env) {
  const censusKey = env.CENSUS_API_KEY;
  const variables = Object.keys(INDUSTRY_VARS).join(',');
  
  const url = `https://api.census.gov/data/2022/acs/acs5?get=NAME,${variables}&for=county:${county}&in=state:${state}&key=${censusKey}`;
  
  try {
    const response = await fetch(url);
    const data = await response.json();
    
    if (!data || data.length < 2) {
      return { error: 'Census API returned no data', url: url };
    }

    // Parse response: headers are row 0, values are row 1
    const headers = data[0];
    const values = data[1];
    
    const industries = {};
    let totalEmployed = 0;
    
    headers.forEach((header, idx) => {
      const value = parseInt(values[idx]) || 0;
      if (INDUSTRY_VARS[header]) {
        industries[INDUSTRY_VARS[header]] = value;
        if (header === 'C24050_001E') {
          totalEmployed = value;
        }
      }
    });

    // Sort industries by count (descending)
    const sorted = Object.entries(industries)
      .sort((a, b) => b[1] - a[1])
      .reduce((acc, [key, val]) => ({ ...acc, [key]: val }), {});

    return {
      success: true,
      total_employed: totalEmployed,
      industries: sorted,
      timestamp: new Date().toISOString()
    };

  } catch (error) {
    return { error: error.message };
  }
}

// ============================================================================
// Function: Handle /api/census requests
// ============================================================================
async function handleCensusRequest(zip, env) {
  // Normalize ZIP (remove leading zeros for lookup)
  const normalizedZip = zip.replace(/^0+/, '') || zip;
  
  const countyInfo = ZIP_TO_COUNTY[normalizedZip];
  
  if (!countyInfo) {
    return {
      error: 'ZIP code not found',
      zip_requested: zip,
      zip_normalized: normalizedZip,
      available_samples: ['91302', '1001', '10001'] // Show examples
    };
  }

  // Call Census API
  const censusData = await getCensusIndustries(countyInfo.state, countyInfo.county, env);

  if (censusData.error) {
    return {
      error: 'Census API error',
      details: censusData.error,
      zip: zip,
      county: countyInfo.county_name,
      state: countyInfo.state_name
    };
  }

  return {
    success: true,
    zip: zip,
    county: countyInfo.county_name,
    state: countyInfo.state_name,
    total_employed: censusData.total_employed,
    industries: censusData.industries,
    timestamp: censusData.timestamp
  };
}

// ============================================================================
// Main Worker Handler
// ============================================================================
export default {
  async fetch(request, env) {
    const url = new URL(request.url);
    const pathname = url.pathname;

    // Route: GET /api/census?zip=91302
    if (pathname === '/api/census' && request.method === 'GET') {
      const zip = url.searchParams.get('zip');
      
      if (!zip) {
        return new Response(
          JSON.stringify({ error: 'ZIP code required. Usage: /api/census?zip=91302' }),
          { status: 400, headers: { 'Content-Type': 'application/json' } }
        );
      }

      const result = await handleCensusRequest(zip, env);
      return new Response(JSON.stringify(result, null, 2), {
        headers: { 'Content-Type': 'application/json' },
        status: result.error ? 400 : 200
      });
    }

    // Health check
    if (pathname === '/api/health') {
      return new Response(JSON.stringify({ status: 'ok', service: 'census' }), {
        headers: { 'Content-Type': 'application/json' }
      });
    }

    return new Response('Endpoint not found', { status: 404 });
  }
};
